resources.string:
Add-WindowsCapability -Online -Name OpenSSH.Server~~~~0.0.1.0;
Start-Service sshd;
Set-Service -Name sshd -StartupType Automatic;

mkdir "$HOME\\.ssh" -Force;
ssh-keygen -t ed25519 -f "$HOME\\.ssh\\remodex_ed25519";

When asked, choose a passphrase for the recommended secure setup, or press Enter to leave it empty.

# Non-admin Windows users:
Get-Content "$HOME\\.ssh\\remodex_ed25519.pub" | `
  Add-Content "$HOME\\.ssh\\authorized_keys";

# Admin Windows users:
Set-Content `
  -Path "C:\\ProgramData\\ssh\\administrators_authorized_keys" `
  -Value (Get-Content "$HOME\\.ssh\\remodex_ed25519.pub" -Raw) `
  -Encoding ascii;

icacls "C:\\ProgramData\\ssh\\administrators_authorized_keys" `
  /inheritance:r;
icacls "C:\\ProgramData\\ssh\\administrators_authorized_keys" `
  /grant:r "SYSTEM:F";
icacls "C:\\ProgramData\\ssh\\administrators_authorized_keys" `
  /grant:r "BUILTIN\\Administrators:F";

Restart-Service sshd;

whoami;
ipconfig;
notepad "$HOME\\.ssh\\remodex_ed25519";

Host: your PC IPv4 address from ipconfig
Port: 22
Username: only the part after \\ from whoami
Private key: full contents of remodex_ed25519, not the .pub file
Passphrase: the passphrase you chose, or empty
